def solve(n):
    if n == 1:
        return 1, [1]
    if n < 10:
        return 1, [n]
    if n < 20:
        return 2, [10, n - 10]
    if n < 30:
        return 2, [20, n - 20]
    if n < 40:
        return 2, [30, n - 30]
    if n < 50:
        return 2, [40, n - 40]
    if n < 60:
        return 2, [50, n - 50]
    if n < 70:
        return 2, [60, n - 60]
    if n < 80:
        return 2, [70, n - 70]
    if n < 90:
        return 2, [80, n - 80]
    if n < 100:
        return 2, [90, n - 90]
    return 3, [9, 9, n - 18]

n = int(input())
k, d = solve(n)
print(k)
print(*d)
